// ============================================
// CODE: PII MASKING -- regex SĐT VN + ten rieng -> mask tokens
// Outputs BOTH maskedMessage (for logging) and originalMessage (for AI processing)
// CRITICAL-2 fix: AI Agent gets originalMessage with real phone numbers
// ============================================
const triggerData = $input.first().json;
let message = triggerData.data?.content || triggerData.data?.text || '';
const originalMessage = message;
const phoneMap = [];
const nameMap = [];

// 1. Mask VN phone numbers: 0[3|5|7|8|9]xxxxxxxx
// CRITICAL-3 fix: phone regex works on original message (unmasked)
const phoneRe = /\b(0[35789]\d{8})\b/g;
message = message.replace(phoneRe, (m) => {
  const id = phoneMap.length;
  phoneMap.push({ mask: `[PHONE_${id}]`, real: m });
  return `[PHONE_${id}]`;
});

// 2. Mask names after keywords: ten, anh, chi, em la, toi la
// HIGH-3 fix: use String.replace() with callback instead of while/exec loop
const nameKw = /\b(?:tên|Tôi là|Em là|Anh là|Chị là)\s+([A-ZÀ-Ỹ][a-zà-ỹ]{1,15})\b/gi;
message = message.replace(nameKw, (fullMatch, name) => {
  const id = nameMap.length;
  const placeholder = `[NAME_${id}]`;
  nameMap.push({ mask: placeholder, real: name });
  return fullMatch.replace(name, placeholder);
});

return [{
  json: {
    originalMessage: originalMessage,
    maskedMessage: message,
    phoneMap,
    nameMap,
    senderId: triggerData.data?.fromId || triggerData.data?.senderId || 'unknown',
    senderName: triggerData.data?.senderName || 'Khách hàng',
    threadId: triggerData.threadId || ''
  }
}];

// ============================================
// CODE: CHUẨN BỊ CONTEXT CHO AI AGENT
// Updated: reads from PII Masking output, forwards originalMessage
// HIGH-1 fix: originalMessage is forwarded through pipeline
// CRITICAL-2 fix: AI Agent receives originalMessage (unmasked)
// ============================================

// 1. Lấy dữ liệu bảng giá (tất cả rows từ Google Sheets)
const priceRows = $input.all();
let priceText = '';

if (priceRows.length > 0) {
  priceText = priceRows.map(r => {
    const svc = r.json['Dịch vụ'] || r.json['dich_vu'] || r.json['Service'] || '';
    const price = r.json['Giá'] || r.json['gia'] || r.json['Price'] || '';
    const desc = r.json['Mô tả'] || r.json['mo_ta'] || r.json['Description'] || '';
    if (!svc) return '';
    return `• ${svc}: ${price}${desc ? ' — ' + desc : ''}`;
  }).filter(Boolean).join('\n');
}

if (!priceText) {
  priceText = '(Chưa có dữ liệu giá — tư vấn chung, hướng khách đặt lịch)';
}

// 2. Lấy dữ liệu từ PII Masking node
const piiData = $input.first().json;

return [{
  json: {
    priceSection: priceText,
    // CRITICAL-2: AI Agent uses originalMessage (real phone numbers)
    customerMessage: piiData.originalMessage || '',
    // MEDIUM-5: maskedMessage forwarded for Log Chat (PII-protected)
    maskedMessage: piiData.maskedMessage || piiData.originalMessage || '',
    phoneMap: piiData.phoneMap || [],
    nameMap: piiData.nameMap || [],
    originalMessage: piiData.originalMessage || '',
    senderId: piiData.senderId || 'unknown',
    senderName: piiData.senderName || 'Khách hàng',
    threadId: piiData.threadId || ''
  }
}];

// ============================================
// PARSE BOOKING v3 — Error fallback + Log data
// ============================================

const triggerData = $('Zalo Message Trigger').item.json;
const senderId = triggerData.data?.fromId || triggerData.data?.senderId || 'unknown';
const senderName = triggerData.data?.senderName || 'Khách hàng';
const customerMessage = triggerData.data?.content || triggerData.data?.text || '';
const threadId = triggerData.threadId || '';
const timestamp = new Date().toLocaleString('vi-VN', { timeZone: 'Asia/Ho_Chi_Minh' });

// ============ FALLBACK KHI API LỖI ============
const aiOutput = $input.first().json.output || '';
const hasError = !aiOutput || $input.first().json.error;

if (hasError) {
  return [{
    json: {
      isBooking: false,
      bookingData: null,
      replyText: 'Dạ hiện em đang bận hỗ trợ khách khác. Chị để lại số điện thoại, em gọi lại tư vấn cho chị ngay nhé! 💖',
      senderId: senderId,
      senderName: senderName,
      rawAiOutput: aiOutput,
      threadId: threadId,
      isError: true,
      messageType: 'Fallback (lỗi API)',
      customerMessage: customerMessage,
      timestamp: timestamp
    }
  }];
}

// ============ PHÂN TÍCH BOOKING ============
let isBooking = false;
let bookingData = null;
let replyText = '';

try {
  const jsonMatch = aiOutput.match(/\{[\s\S]*"booking"[\s\S]*\}/);
  if (jsonMatch) {
    const parsed = JSON.parse(jsonMatch[0]);
    if (parsed.booking === true && parsed.phone) {
      isBooking = true;
      bookingData = {
        name: parsed.name || 'Không rõ',
        phone: parsed.phone || '',
        service: parsed.service || 'Không rõ',
        note: parsed.note || '',
        timestamp: timestamp
      };
      replyText = `✅ Em đã ghi nhận lịch hẹn của chị ${bookingData.name} rồi ạ!\n\n📋 Thông tin:\n• Dịch vụ: ${bookingData.service}\n• Ghi chú: ${bookingData.note || 'Không có'}\n\nEm sẽ liên hệ xác nhận lại với chị trong thời gian sớm nhất. Cảm ơn chị đã tin tưởng! 💖`;
    }
  }
} catch (e) {
  isBooking = false;
}

if (!isBooking) {
  replyText = aiOutput;
}

// ============ PHÂN LOẠI TIN NHẮN ============
let messageType = 'Tư vấn';
if (isBooking) {
  messageType = 'Đặt lịch';
} else {
  const lowerMsg = customerMessage.toLowerCase();
  if (lowerMsg.match(/giá|bao nhiêu|cost|price|phí|tiền|đắt|rẻ/)) {
    messageType = 'Hỏi giá';
  } else if (lowerMsg.match(/phàn nàn|tệ|kém|không hài lòng|chửi|ghét|bực|tồi/)) {
    messageType = 'Phàn nàn';
  } else if (lowerMsg.match(/giờ|địa chỉ|ở đâu|map|chỉ đường/)) {
    messageType = 'Hỏi thông tin';
  }
}

return [{
  json: {
    isBooking: isBooking,
    bookingData: bookingData,
    replyText: replyText,
    senderId: senderId,
    senderName: senderName,
    rawAiOutput: aiOutput,
    threadId: threadId,
    isError: false,
    messageType: messageType,
    customerMessage: customerMessage,
    timestamp: timestamp
  }
}];

// Tạo tin nhắn báo chủ spa
const data = $input.first().json;
const b = data.bookingData;

const ownerMsg = `🔔 KHÁCH HÀNG MỚI ĐẶT LỊCH\n\n👤 Tên: ${b.name}\n📞 SĐT: ${b.phone}\n💇 Dịch vụ: ${b.service}\n📝 Ghi chú: ${b.note || 'Không có'}\n⏰ Thời gian: ${b.timestamp}\n\nXác nhận lịch hẹn với khách ngay nhé!`;

return [{
  json: {
    ownerMessage: ownerMsg,
    threadId: data.threadId
  }
}];
